import {
  type AlwaysAllowDir,
  type FailReturn,
  type SubmitHandler,
  component$,
  useContext,
  useTask$,
} from "@builder.io/qwik";
import {
  type DocumentHead,
  type RequestHandler,
  Form,
  globalAction$,
  routeAction$,
  routeLoader$,
  server$,
  zod$,
  z,
} from "@builder.io/qwik-city";
import { createRequire } from "node:module";

// ============================================================================
// Server-only helpers (never serialized into the client bundle).
// All filesystem access is confined to functions guarded by `server$`,
// `routeLoader$`, and `routeAction$` so that `node:fs` / `node:path` are
// never imported on the client.
// ============================================================================

const require = createRequire(import.meta.url);
import { promises as fs } from "node:fs/promises";
import path from "node:path";

const UPLOADS_DIR = path.join(process.cwd(), "public", "uploads");

const ALLOWED_EXTENSIONS = [".png", ".jpg", ".jpeg", ".gif", ".webp"];
const MAX_FILE_SIZE = 2 * 1024 * 1024; // 2 MiB

/** Ensure the uploads directory exists. */
async function ensureUploadsDir(): Promise<void> {
  await fs.mkdir(UPLOADS_DIR, { recursive: true });
}

/** Return a sorted list of filenames stored in the uploads directory. */
async function listUploadedFiles(): Promise<string[]> {
  try {
    const entries = await fs.readdir(UPLOADS_DIR, { withFileTypes: true });
    return entries
      .filter((entry) => entry.isFile())
      .map((entry) => entry.name)
      .sort((a, b) => a.localeCompare(b));
  } catch (err: any) {
    if (err && err.code === "ENOENT") {
      return [];
    }
    throw err;
  }
}

/** Validate a single uploaded file's extension and size. */
function validateUploadFile(file: File): string | null {
  const name = (file.name || "").toLowerCase();
  const ext = path.extname(name);

  if (!ALLOWED_EXTENSIONS.includes(ext)) {
    return `Files of type "${ext || "unknown"}" are not allowed. Allowed: ${ALLOWED_EXTENSIONS.join(", ")}`;
  }
  if (file.size > MAX_FILE_SIZE) {
    return `File is too large (${file.size} bytes). Maximum is ${MAX_FILE_SIZE} bytes (2 MiB).`;
  }
  return null;
}

// ============================================================================
// routeLoader$ — reads the uploads directory on the server and exposes the
// list of filenames to the component for rendering.
// ============================================================================

export const useImages = routeLoader$(async () => {
  await ensureUploadsDir();
  const files = await listUploadedFiles();
  return files.map((name) => ({
    name,
    src: `/uploads/${name}`,
  }));
});

// ============================================================================
// routeAction$ — receives the multipart/form-data submission, validates the
// file, and persists it to the local filesystem. Rejections are surfaced via
// the field-error mechanism.
// ============================================================================

export const useUpload = routeAction$(
  async (data, { fail }) => {
    const file = data.image;

    if (!file || !(file instanceof File) || file.size === 0) {
      return fail(400, {
        fieldErrors: {
          image: "Please select an image file to upload.",
        },
      });
    }

    const validationError = validateUploadFile(file);
    if (validationError) {
      return fail(400, {
        fieldErrors: {
          image: validationError,
        },
      });
    }

    // Read the file bytes and write them to disk.
    const buffer = Buffer.from(await file.arrayBuffer());
    await ensureUploadsDir();

    // Preserve the uploaded file's name. We sanitize the basename to avoid
    // any path traversal via the filename.
    const safeBase = path.basename(file.name);
    const dest = path.join(UPLOADS_DIR, safeBase);

    await fs.writeFile(dest, buffer);

    return {
      success: true,
      filename: safeBase,
    };
  },
  zod$({
    image: z.instanceof(File),
  }),
);

// ============================================================================
// UI component
// ============================================================================

export default component$(() => {
  const images = useImages();
  const action = useUpload();

  return (
    <main style={{ "max-width": "960px", margin: "0 auto", padding: "1.5rem" }}>
      <h1>Image Gallery</h1>
      <p>
        Upload an image (PNG, JPG, JPEG, GIF, or WEBP) up to 2 MiB. Uploaded
        images are stored locally and shown below.
      </p>

      <Form action={action} encType="multipart/form-data">
        <div style={{ display: "flex", gap: "0.5rem", alignItems: "center" }}>
          <input
            type="file"
            name="image"
            accept="image/png,image/jpeg,image/gif,image/webp"
            required
          />
          <button type="submit">Upload</button>
        </div>
      </Form>

      {action.value?.fieldErrors?.image && (
        <p
          role="alert"
          style={{ color: "crimson", "margin-top": "0.75rem" }}
        >
          {action.value.fieldErrors.image}
        </p>
      )}

      {action.value?.success && (
        <p style={{ color: "green", "margin-top": "0.75rem" }}>
          Uploaded {action.value.filename}.
        </p>
      )}

      <hr style={{ margin: "1.5rem 0" }} />

      <h2>Gallery</h2>
      {images.value.length === 0 ? (
        <p>No images uploaded yet.</p>
      ) : (
        <div
          style={{
            display: "grid",
            "grid-template-columns":
              "repeat(auto-fill, minmax(180px, 1fr))",
            gap: "1rem",
          }}
        >
          {images.value.map((img) => (
            <figure
              key={img.name}
              style={{ margin: 0, display: "flex", "flex-direction": "column" }}
            >
              <img
                src={img.src}
                alt={img.name}
                style={{
                  width: "100%",
                  height: "180px",
                  "object-fit": "cover",
                  border: "1px solid #ccc",
                  "border-radius": "4px",
                }}
              />
              <figcaption
                style={{
                  "font-size": "0.8rem",
                  "margin-top": "0.25rem",
                  "word-break": "break-all",
                }}
              >
                {img.name}
              </figcaption>
            </figure>
